UPDATE tbl_board
SET title = #{title},
content =
#{content},
writer = #{writer}
WHERE bno = #{bno}

mapper.delete:
DELETE FROM tbl_board_like
WHERE bno = #{bno} AND
userid = #{userid} AND type = #{type}

mapper.update:
UPDATE tbl_board
SET likecnt = likecnt + #{amount}
WHERE bno = #{bno}

UPDATE tbl_board
SET dislikecnt = dislikecnt +
#{amount}
WHERE bno = #{bno}

mapper.select:

SELECT * FROM (
    SELECT /*+INDEX_DESC(tbl_board pk_board) */
        rownum rn, b.bno, b.title, b.content, b.writer, b.regdate, b.updatedate, b.cat_id, c.cat_name
    FROM tbl_board b
    LEFT JOIN tbl_category c ON b.cat_id = c.cat_id  
    WHERE b.cat_id = 11 
    AND rownum <= #{pageNum} * #{amount}
) WHERE rn > (#{pageNum} - 1) * #{amount}

SELECT * FROM ( SELECT b.bno, b.title, b.content, b.writer, b.regdate, b.replycnt, c.cat_name, c.cat_slug FROM tbl_board b LEFT JOIN tbl_category c ON b.cat_id = c.cat_id
AND c.cat_name = #{category}
ORDER BY b.bno DESC ) WHERE ROWNUM <= 20
